 1→import { readFileSync, writeFileSync, existsSync, mkdirSync } from "node:fs";
 2→import { join } from "node:path";
 3→import { homedir } from "node:os";
 4→
 5→const BRAIN_DIR = join(homedir(), ".brain");
 6→const CONFIG_PATH = join(BRAIN_DIR, "config.json");
 7→const DIR_CACHE_PATH = join(BRAIN_DIR, "dir-cache.json");
 8→
 9→export type BrainConfig = {
10→  server_url: string;
11→  workspace: string;
12→  api_key: string;
13→};
14→
15→export type DirCacheEntry = {
16→  project_id: string;
17→  project_name: string;
18→  last_session?: string;
19→  session_id?: string;
20→};
21→
22→function ensureDir(): void {
23→  if (!existsSync(BRAIN_DIR)) {
24→    mkdirSync(BRAIN_DIR, { recursive: true });
25→  }
26→}
27→
28→export function loadConfig(): BrainConfig | undefined {
29→  if (!existsSync(CONFIG_PATH)) return undefined;
30→  try {
31→    return JSON.parse(readFileSync(CONFIG_PATH, "utf-8")) as BrainConfig;
32→  } catch {
33→    return undefined;
34→  }
35→}
36→
37→export function saveConfig(config: BrainConfig): void {
38→  ensureDir();
39→  writeFileSync(CONFIG_PATH, JSON.stringify(config, null, 2) + "\n");
40→}
41→
42→export function loadDirCache(): Record<string, DirCacheEntry> {
43→  if (!existsSync(DIR_CACHE_PATH)) return {};
44→  try {
45→    return JSON.parse(readFileSync(DIR_CACHE_PATH, "utf-8")) as Record<string, DirCacheEntry>;
46→  } catch {
47→    return {};
48→  }
49→}
50→
51→export function saveDirCache(cache: Record<string, DirCacheEntry>): void {
52→  ensureDir();
53→  writeFileSync(DIR_CACHE_PATH, JSON.stringify(cache, null, 2) + "\n");
54→}
55→
56→export function getDirCacheEntry(directory: string): DirCacheEntry | undefined {
57→  const cache = loadDirCache();
58→  return cache[directory];
59→}
60→
61→export function setDirCacheEntry(directory: string, entry: DirCacheEntry): void {
62→  const cache = loadDirCache();
63→  cache[directory] = entry;
64→  saveDirCache(cache);
65→}
66→
67→export function requireConfig(): BrainConfig {
68→  const config = loadConfig();
69→  if (!config) {
70→    console.error("Brain not configured. Run: brain init");
71→    process.exit(1);
72→  }
73→  return config;
74→}
