 38→      project_id: z.string().describe("Project ID"),
 39→      area: z.string().optional().describe("Category filter: engineering, research, marketing, operations, design, sales"),
 40→    },
 41→    async (input) => {
 42→      const result = await client.getDecisions(input);
 43→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 44→    },
 45→  );
 46→
 47→  server.tool(
 48→    "get_task_dependencies",
 49→    "Get full dependency tree for a task: what it depends on, what depends on it, and its subtasks.",
 50→    {
 51→      task_id: z.string().describe("Task ID"),
 52→    },
 53→    async (input) => {
 54→      const result = await client.getTaskDependencies(input);
 55→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 56→    },
 57→  );
 58→
 59→  server.tool(
 60→    "get_architecture_constraints",
 61→    "Get constraints that apply to a project: confirmed decisions (hard constraints) and open observations (warnings/conflicts).",
 62→    {
 63→      project_id: z.string().describe("Project ID"),
 64→      area: z.string().optional().describe("Category filter"),
 65→    },
 66→    async (input) => {
