 68→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 69→    },
 70→  );
 71→
 72→  server.tool(
 73→    "get_recent_changes",
 74→    "Get entities that changed since a timestamp. Use to see what happened while you were away.",
 75→    {
 76→      project_id: z.string().optional().describe("Project ID to scope changes"),
 77→      since: z.string().describe("ISO timestamp to get changes since"),
 78→    },
 79→    async (input) => {
 80→      const result = await client.getChanges(input);
