474→function formatTimeAgo(isoString: string): string {
475→  const diff = Date.now() - new Date(isoString).getTime();
476→  const minutes = Math.floor(diff / 60000);
477→  if (minutes < 1) return "just now";
478→  if (minutes < 60) return `${minutes}m ago`;
479→  const hours = Math.floor(minutes / 60);
480→  if (hours < 24) return `${hours}h ago`;
481→  return `${Math.floor(hours / 24)}d ago`;
482→}
