11→async function main(): Promise<void> {
12→  switch (command) {
13→    case "init":
14→      await runInit();
15→      break;
16→
17→    case "system":
18→      switch (subcommand) {
19→        case "load-context":
20→          await runLoadContext();
21→          break;
22→        case "set-project":
23→          if (!args[2]) {
24→            console.error("Usage: brain system set-project <project-id>");
25→            process.exit(1);
26→          }
27→          await runSetProject(args[2]);
28→          break;
29→        case "check-updates":
30→          await runCheckUpdates();
31→          break;
32→        case "end-session":
33→          await runEndSession();
34→          break;
35→        default:
36→          console.error(`Unknown system subcommand: ${subcommand}`);
37→          console.error("Available: load-context, set-project, check-updates, end-session");
38→          process.exit(1);
39→      }
40→      break;
41→
42→    case "check-commit":
43→      await runCheckCommit();
44→      break;
45→
46→    case "log-commit":
47→      await runLogCommit();
48→      break;
49→
50→    case "mcp":
51→      // MCP stdio server — import dynamically to avoid loading deps unless needed
52→      const { runMcpServer } = await import("./mcp-server");
53→      await runMcpServer();
54→      break;
55→
56→    case "help":
57→    case "--help":
58→    case "-h":
59→      printHelp();
60→      break;
61→
62→    default:
63→      if (command) {
64→        console.error(`Unknown command: ${command}`);
65→      }
66→      printHelp();
67→      process.exit(command ? 1 : 0);
68→  }
