 1→#!/usr/bin/env bun
 2→
 3→import { runInit } from "./commands/init";
 4→import { runLoadContext, runSetProject, runCheckUpdates, runEndSession } from "./commands/system";
 5→import { runCheckCommit, runLogCommit } from "./commands/git-hooks";
 6→
 7→const args = process.argv.slice(2);
 8→const command = args[0];
 9→const subcommand = args[1];
10→
11→async function main(): Promise<void> {
12→  switch (command) {
13→    case "init":
14→      await runInit();
15→      break;
16→
17→    case "system":
18→      switch (subcommand) {
19→        case "load-context":
20→          await runLoadContext();
21→          break;
22→        case "set-project":
23→          if (!args[2]) {
24→            console.error("Usage: brain system set-project <project-id>");
25→            process.exit(1);
26→          }
27→          await runSetProject(args[2]);
28→          break;
29→        case "check-updates":
30→          await runCheckUpdates();
31→          break;
32→        case "end-session":
33→          await runEndSession();
34→          break;
35→        default:
36→          console.error(`Unknown system subcommand: ${subcommand}`);
37→          console.error("Available: load-context, set-project, check-updates, end-session");
38→          process.exit(1);
39→      }
40→      break;
41→
42→    case "check-commit":
43→      await runCheckCommit();
44→      break;
45→
46→    case "log-commit":
47→      await runLogCommit();
48→      break;
49→
50→    case "mcp":
51→      // MCP stdio server — import dynamically to avoid loading deps unless needed
52→      const { runMcpServer } = await import("./mcp-server");
53→      await runMcpServer();
54→      break;
55→
56→    case "help":
57→    case "--help":
58→    case "-h":
59→      printHelp();
60→      break;
61→
62→    default:
63→      if (command) {
64→        console.error(`Unknown command: ${command}`);
65→      }
66→      printHelp();
67→      process.exit(command ? 1 : 0);
68→  }
69→}
70→
71→function printHelp(): void {
72→  console.log(`
73→brain — Connect coding agents to the Brain knowledge graph
74→
75→Usage:
76→  brain init                     Set up workspace auth and git hooks
77→  brain system load-context      Load project context (SessionStart hook)
78→  brain system set-project <id>  Set project for current directory
79→  brain system check-updates     Check for graph updates (UserPromptSubmit hook)
80→  brain system end-session       End agent session (SessionEnd hook)
81→  brain check-commit             Pre-commit hook: check for task completion
82→  brain log-commit               Deprecated no-op (GitHub webhook ingests commits)
83→  brain mcp                      Start MCP stdio server
84→
85→Environment:
86→  BRAIN_SERVER_URL      Brain server URL (default: http://localhost:3000)
87→  BRAIN_WORKSPACE_ID    Workspace ID (required for init)
88→`);
89→}
90→
91→main().catch((error) => {
92→  console.error(error instanceof Error ? error.message : error);
93→  process.exit(1);
94→});
95→

