  1→import { writeFileSync, readFileSync, existsSync, mkdirSync, chmodSync, unlinkSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { saveConfig } from "../config";
  4→import { BrainHttpClient } from "../http-client";
  5→
  6→const DEFAULT_SERVER_URL = "http://localhost:3000";
  7→
  8→export async function runInit(): Promise<void> {
  9→  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 10→
 11→  console.log("Connecting to Brain server...\n");
 12→
 13→  // Fetch workspaces — for now, use the default workspace
 14→  // In future: prompt for workspace selection
 15→  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 16→  if (!workspaceId) {
 17→    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 18→    console.error("Find it in the Brain web UI or the database.");
 19→    process.exit(1);
 20→  }
 21→
 22→  try {
 23→    // Generate API key
 24→    const initResult = await BrainHttpClient.initApiKey(serverUrl, workspaceId);
 25→
 26→    // Save config
 27→    saveConfig({
 28→      server_url: serverUrl,
 29→      workspace: workspaceId,
 30→      api_key: initResult.api_key,
 31→    });
 32→
 33→    // Install git hooks
 34→    installGitHooks();
 35→
 36→    console.log(`Connected to workspace: ${initResult.workspace.name} (${workspaceId})\n`);
 37→    console.log("Configuration saved to ~/.brain/config.json");
 38→    console.log("Plugin hooks active:");
 39→    console.log("  SessionStart  -> infers project, loads context");
 40→    console.log("  UserPromptSubmit -> checks for updates");
 41→    console.log("  Stop          -> catches unlogged decisions + questions");
 42→    console.log("  SessionEnd    -> logs session to graph");
 43→    console.log("");
 44→    console.log("Git hooks installed:");
 45→    console.log("  pre-commit    -> checks if commit resolves tasks");
 46→    console.log("  post-commit   -> not installed (GitHub webhook is commit source of truth)");
 47→  } catch (error) {
 48→    console.error("Failed to connect:", error instanceof Error ? error.message : error);
 49→    process.exit(1);
 50→  }
 51→}
 52→
 53→function installGitHooks(): void {
 54→  // Find .git directory by walking up
 55→  let dir = process.cwd();
 56→  let gitDir: string | undefined;
 57→
 58→  while (dir !== "/") {
 59→    const candidate = join(dir, ".git");
 60→    if (existsSync(candidate)) {
 61→      gitDir = candidate;
 62→      break;
 63→    }
 64→    dir = join(dir, "..");
 65→  }
 66→
 67→  if (!gitDir) {
 68→    console.log("\nNo .git directory found — skipping git hook installation.");
 69→    return;
 70→  }
 71→
 72→  const hooksDir = join(gitDir, "hooks");
 73→  if (!existsSync(hooksDir)) {
 74→    mkdirSync(hooksDir, { recursive: true });
 75→  }
 76→
 77→  const preCommitPath = join(hooksDir, "pre-commit");
 78→  const postCommitPath = join(hooksDir, "post-commit");
 79→  const preCommitScript = `#!/bin/sh
 80→# Brain pre-commit hook: check for task completion and unlogged decisions
 81→brain check-commit
 82→`;
 83→
 84→  // Only install if no existing hook
 85→  if (!existsSync(preCommitPath)) {
 86→    writeFileSync(preCommitPath, preCommitScript);
 87→    chmodSync(preCommitPath, 0o755);
 88→  } else {
 89→    console.log("  pre-commit hook already exists — skipping");
 90→  }
 91→  if (existsSync(postCommitPath)) {
 92→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
 93→    const isBrainManagedPostCommit = postCommitContent.includes("Brain post-commit hook")
 94→      && postCommitContent.includes("brain log-commit");
 95→    if (isBrainManagedPostCommit) {
 96→      unlinkSync(postCommitPath);
 97→      console.log("  removed legacy Brain post-commit hook (webhook is source of truth)");
 98→    } else {
 99→      console.log("  existing post-commit hook left unchanged");
100→    }
101→  }
102→}
