190→/**
191→ * brain system end-session
192→ * Called by SessionEnd hook.
193→ */
194→export async function runEndSession(): Promise<void> {
195→  const config = requireConfig();
196→  const client = new BrainHttpClient(config);
197→  const cwd = process.cwd();
198→  const cached = getDirCacheEntry(cwd);
199→
200→  if (!cached) return; // No project mapped — nothing to end
201→
202→  try {
203→    // Read stdin (Claude Code pipes Stop hook JSON)
204→    let stdinText = "";
205→    try {
206→      const chunks: Buffer[] = [];
207→      for await (const chunk of Bun.stdin.stream()) {
208→        chunks.push(Buffer.from(chunk));
209→      }
210→      stdinText = Buffer.concat(chunks).toString("utf-8").trim();
211→    } catch {
212→      // stdin not available or empty
213→    }
214→
215→    // Parse the summary payload
216→    let summary = "Session ended without summary";
217→    let decisionsMade: string[] | undefined;
218→    let questionsAsked: string[] | undefined;
219→    let tasksProgressed: Array<{ task_id: string; from_status: string; to_status: string }> | undefined;
220→    let filesChanged: Array<{ path: string; change_type: string }> | undefined;
221→    let observationsLogged: string[] | undefined;
222→
223→    if (stdinText) {
224→      const parsed = JSON.parse(stdinText) as Record<string, unknown>;
225→      if (parsed.decision === "block") {
226→        const reason = typeof parsed.reason === "string" ? parsed.reason : "Stop hook returned block decision";
227→        throw new Error(`Session end blocked: ${reason}`);
228→      }
229→      if (parsed.decision !== "approve") {
230→        throw new Error("Stop hook payload must include decision=\"approve\" or decision=\"block\"");
231→      }
232→      if (typeof parsed.summary !== "string" || parsed.summary.trim().length === 0) {
233→        throw new Error("Stop hook payload must include a non-empty string summary");
234→      }
235→      summary = parsed.summary.trim();
236→
237→      if (parsed.decisions_made !== undefined) {
238→        if (!Array.isArray(parsed.decisions_made) || !parsed.decisions_made.every((v) => typeof v === "string")) {
239→          throw new Error("decisions_made must be an array of string ids");
240→        }
241→        decisionsMade = parsed.decisions_made;
242→      }
243→
244→      if (parsed.questions_asked !== undefined) {
245→        if (!Array.isArray(parsed.questions_asked) || !parsed.questions_asked.every((v) => typeof v === "string")) {
246→          throw new Error("questions_asked must be an array of string ids");
247→        }
248→        questionsAsked = parsed.questions_asked;
249→      }
250→
251→      if (parsed.tasks_progressed !== undefined) {
252→        if (!Array.isArray(parsed.tasks_progressed)) {
253→          throw new Error("tasks_progressed must be an array");
254→        }
255→        tasksProgressed = parsed.tasks_progressed.map((entry) => {
256→          if (!entry || typeof entry !== "object") {
257→            throw new Error("tasks_progressed entries must be objects");
258→          }
259→          const row = entry as Record<string, unknown>;
260→          if (
261→            typeof row.task_id !== "string" ||
262→            typeof row.from_status !== "string" ||
263→            typeof row.to_status !== "string"
264→          ) {
265→            throw new Error("tasks_progressed entries must include string task_id, from_status, and to_status");
266→          }
267→          return {
268→            task_id: row.task_id,
269→            from_status: row.from_status,
270→            to_status: row.to_status,
271→          };
272→        });
273→      }
274→
275→      if (parsed.files_changed !== undefined) {
276→        if (!Array.isArray(parsed.files_changed)) {
277→          throw new Error("files_changed must be an array");
278→        }
279→        filesChanged = parsed.files_changed.map((entry) => {
280→          if (!entry || typeof entry !== "object") {
281→            throw new Error("files_changed entries must be objects");
282→          }
283→          const row = entry as Record<string, unknown>;
284→          if (typeof row.path !== "string" || typeof row.change_type !== "string") {
285→            throw new Error("files_changed entries must include string path and change_type");
286→          }
287→          if (!["created", "modified", "deleted"].includes(row.change_type)) {
288→            throw new Error("files_changed.change_type must be one of: created, modified, deleted");
289→          }
290→          return { path: row.path, change_type: row.change_type };
291→        });
292→      }
293→
294→      if (parsed.observations_logged !== undefined) {
295→        if (!Array.isArray(parsed.observations_logged) || !parsed.observations_logged.every((v) => typeof v === "string")) {
296→          throw new Error("observations_logged must be an array of string ids");
297→        }
298→        observationsLogged = parsed.observations_logged;
299→      }
300→    }
301→
302→    // Get session_id from cache, or create a session as fallback
303→    let sessionId = cached.session_id;
304→    if (!sessionId) {
305→      const session = await client.sessionStart({
306→        agent: "claude-code",
307→        project_id: cached.project_id,
308→      });
309→      sessionId = session.session_id;
310→    }
311→
312→    await client.sessionEnd({
313→      session_id: sessionId,
314→      summary,
315→      decisions_made: decisionsMade,
316→      questions_asked: questionsAsked,
317→      tasks_progressed: tasksProgressed,
318→      files_changed: filesChanged,
319→      observations_logged: observationsLogged,
320→    });
321→
322→    // Clear session_id from cache
323→    setDirCacheEntry(cwd, { ...cached, session_id: undefined });
324→  } catch (error) {
325→    console.error(`Brain: Failed to end session: ${error instanceof Error ? error.message : error}`);
326→  }
327→}
