429→  const observations = p.observations as Array<{ text: string; severity: string }> | undefined;
430→  if (observations?.length) {
431→    lines.push("## Observations");
432→    for (const o of observations) {
433→      lines.push(`  - [${o.severity}] ${o.text}`);
434→    }
435→    lines.push("");
436→  }
437→
438→  // Active agent sessions (cross-agent awareness)
439→  type ActiveSession = {
440→    agent: string;
441→    started_at: string;
442→    task?: { id: string; title: string };
443→    provisional_decisions: Array<{ summary: string }>;
444→    observations: Array<{ text: string; severity: string }>;
445→  };
446→  const activeSessions = p.active_sessions as ActiveSession[] | undefined;
447→  if (activeSessions?.length) {
448→    lines.push("## Active Agent Sessions");
449→    for (const s of activeSessions) {
450→      const ago = formatTimeAgo(s.started_at);
451→      lines.push(`  - ${s.agent} (started ${ago})`);
452→      if (s.task) {
453→        lines.push(`    Working on: ${s.task.title}`);
454→      }
455→      if (s.provisional_decisions.length > 0) {
456→        lines.push("    Provisional decisions:");
457→        for (const d of s.provisional_decisions) {
458→          lines.push(`      - ${d.summary}`);
459→        }
460→      }
461→      if (s.observations.length > 0) {
462→        lines.push("    Observations:");
463→        for (const o of s.observations) {
464→          lines.push(`      - [${o.severity}] ${o.text}`);
465→        }
466→      }
467→    }
468→    lines.push("");
469→  }
470→
471→  return lines.join("\n");
472→}
473→
474→function formatTimeAgo(isoString: string): string {
475→  const diff = Date.now() - new Date(isoString).getTime();
476→  const minutes = Math.floor(diff / 60000);
477→  if (minutes < 1) return "just now";
478→  if (minutes < 60) return `${minutes}m ago`;
479→  const hours = Math.floor(minutes / 60);
480→  if (hours < 24) return `${hours}h ago`;
481→  return `${Math.floor(hours / 24)}d ago`;
482→}
