import { writeFileSync, readFileSync, existsSync, mkdirSync, chmodSync, unlinkSync } from "node:fs";
import { join } from "node:path";
import { saveConfig } from "../config";
import { BrainHttpClient } from "../http-client";

const DEFAULT_SERVER_URL = "http://localhost:3000";

export async function runInit(): Promise<void> {
  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;

  console.log("Connecting to Brain server...\n");

  // Fetch workspaces — for now, use the default workspace
  // In future: prompt for workspace selection
  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
  if (!workspaceId) {
    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
    console.error("Find it in the Brain web UI or the database.");
    process.exit(1);
  }

  try {
    // Generate API key
    const initResult = await BrainHttpClient.initApiKey(serverUrl, workspaceId);

    // Save config
    saveConfig({
      server_url: serverUrl,
      workspace: workspaceId,
      api_key: initResult.api_key,
    });

    // Install git hooks
    installGitHooks();

    console.log(`Connected to workspace: ${initResult.workspace.name} (${workspaceId})\n`);
    console.log("Configuration saved to ~/.brain/config.json");
    console.log("Plugin hooks active:");
    console.log("  SessionStart  -> infers project, loads context");
    console.log("  UserPromptSubmit -> checks for updates");
    console.log("  Stop          -> catches unlogged decisions + questions");
    console.log("  SessionEnd    -> logs session to graph");
    console.log("");
    console.log("Git hooks installed:");
    console.log("  pre-commit    -> checks if commit resolves tasks");
    console.log("  post-commit   -> not installed (GitHub webhook is commit source of truth)");
  } catch (error) {
    console.error("Failed to connect:", error instanceof Error ? error.message : error);
    process.exit(1);
  }
}

function installGitHooks(): void {
  // Find .git directory by walking up
  let dir = process.cwd();
  let gitDir: string | undefined;

  while (dir !== "/") {
    const candidate = join(dir, ".git");
    if (existsSync(candidate)) {
      gitDir = candidate;
      break;
    }
    dir = join(dir, "..");
  }

  if (!gitDir) {
    console.log("\nNo .git directory found — skipping git hook installation.");
    return;
  }

  const hooksDir = join(gitDir, "hooks");
  if (!existsSync(hooksDir)) {
    mkdirSync(hooksDir, { recursive: true });
  }

  const preCommitPath = join(hooksDir, "pre-commit");
  const postCommitPath = join(hooksDir, "post-commit");
  const preCommitScript = `#!/bin/sh
# Brain pre-commit hook: check for task completion and unlogged decisions
brain check-commit
`;

  // Only install if no existing hook
  if (!existsSync(preCommitPath)) {
    writeFileSync(preCommitPath, preCommitScript);
    chmodSync(preCommitPath, 0o755);
  } else {
    console.log("  pre-commit hook already exists — skipping");
  }
  if (existsSync(postCommitPath)) {
    const postCommitContent = readFileSync(postCommitPath, "utf-8");
    const isBrainManagedPostCommit = postCommitContent.includes("Brain post-commit hook")
      && postCommitContent.includes("brain log-commit");
    if (isBrainManagedPostCommit) {
      unlinkSync(postCommitPath);
      console.log("  removed legacy Brain post-commit hook (webhook is source of truth)");
    } else {
      console.log("  existing post-commit hook left unchanged");
    }
  }
}

#!/usr/bin/env bun

import { runInit } from "./commands/init";
import { runLoadContext, runSetProject, runCheckUpdates, runEndSession } from "./commands/system";
import { runCheckCommit, runLogCommit } from "./commands/git-hooks";

const args = process.argv.slice(2);
const command = args[0];
const subcommand = args[1];

async function main(): Promise<void> {
  switch (command) {
    case "init":
      await runInit();
      break;

    case "system":
      switch (subcommand) {
        case "load-context":
          await runLoadContext();
          break;
        case "set-project":
          if (!args[2]) {
            console.error("Usage: brain system set-project <project-id>");
            process.exit(1);
          }
          await runSetProject(args[2]);
          break;
        case "check-updates":
          await runCheckUpdates();
          break;
        case "end-session":
          await runEndSession();
          break;
        default:
          console.error(`Unknown system subcommand: ${subcommand}`);
          console.error("Available: load-context, set-project, check-updates, end-session");
          process.exit(1);
      }
      break;

    case "check-commit":
      await runCheckCommit();
      break;

    case "log-commit":
      await runLogCommit();
      break;

    case "mcp":
      // MCP stdio server — import dynamically to avoid loading deps unless needed
      const { runMcpServer } = await import("./mcp-server");
      await runMcpServer();
      break;

    case "help":
    case "--help":
    case "-h":
      printHelp();
      break;

    default:
      if (command) {
        console.error(`Unknown command: ${command}`);
      }
      printHelp();
      process.exit(command ? 1 : 0);
  }
}

function printHelp(): void {
  console.log(`
brain — Connect coding agents to the Brain knowledge graph

Usage:
  brain init                     Set up workspace auth and git hooks
  brain system load-context      Load project context (SessionStart hook)
  brain system set-project <id>  Set project for current directory
  brain system check-updates     Check for graph updates (UserPromptSubmit hook)
  brain system end-session       End agent session (SessionEnd hook)
  brain check-commit             Pre-commit hook: check for task completion
  brain log-commit               Deprecated no-op (GitHub webhook ingests commits)
  brain mcp                      Start MCP stdio server

Environment:
  BRAIN_SERVER_URL      Brain server URL (default: http://localhost:3000)
  BRAIN_WORKSPACE_ID    Workspace ID (required for init)
`);
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : error);
  process.exit(1);
});

