import { readFileSync, writeFileSync, existsSync, mkdirSync, statSync } from "node:fs";
import { join, dirname, resolve } from "node:path";
import { homedir } from "node:os";

const BRAIN_DIR = join(homedir(), ".brain");
const CONFIG_PATH = join(BRAIN_DIR, "config.json");
const DIR_CACHE_PATH = join(BRAIN_DIR, "dir-cache.json");

/** Resolved config for a single repo — shape consumed by BrainHttpClient and all commands. */
export type BrainConfig = {
  server_url: string;
  workspace: string;
  api_key: string;
};

/** Per-repo auth entry in ~/.config/brain.json */
export type RepoConfig = {
  workspace: string;
  api_key: string;
};

/** Root shape of ~/.config/brain.json */
export type BrainGlobalConfig = {
  server_url: string;
  repos: Record<string, RepoConfig>;
};

export type DirCacheEntry = {
  project_id: string;
  project_name: string;
  last_session?: string;
  session_id?: string;
};

// ---------------------------------------------------------------------------
// Git root
// ---------------------------------------------------------------------------

/**
 * Find the main repository root from any path, including worktrees.
 *
 * In a regular repo, `.git` is a directory → that dir is the root.
 * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 * We follow the pointer back to the main repo so all worktrees share one config key.
 */
export function findGitRoot(from: string): string | undefined {
  let dir = from;
  while (dir !== "/") {
    const gitPath = join(dir, ".git");
    if (existsSync(gitPath)) {
      if (statSync(gitPath).isFile()) {
        // Worktree: .git is a file like `gitdir: /main-repo/.git/worktrees/foo`
        return resolveWorktreeMainRoot(gitPath) ?? dir;
      }
      // Regular repo: .git is a directory
      return dir;
    }
    dir = dirname(dir);
  }
  return undefined;
}

/** Read a worktree .git file and resolve to the main repo root. */
function resolveWorktreeMainRoot(gitFile: string): string | undefined {
  try {
    const content = readFileSync(gitFile, "utf-8").trim();
    const match = content.match(/^gitdir:\s*(.+)$/);
    if (!match) return undefined;

    // gitdir points to e.g. /main-repo/.git/worktrees/<name>
    // The main repo root is the parent of the .git directory
    const gitdir = resolve(dirname(gitFile), match[1]);
    // Walk up from gitdir to find the .git directory (strip /worktrees/<name>)
    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
    return dirname(dotGit);
  } catch {
    return undefined;
  }
}

// ---------------------------------------------------------------------------
// Global config (new format: ~/.config/brain.json)
// ---------------------------------------------------------------------------

export function loadGlobalConfig(): BrainGlobalConfig | undefined {
  if (!existsSync(CONFIG_PATH)) return undefined;
  try {
    return JSON.parse(readFileSync(CONFIG_PATH, "utf-8")) as BrainGlobalConfig;
  } catch {
    return undefined;
  }
}

export function saveGlobalConfig(config: BrainGlobalConfig): void {
  const dir = dirname(CONFIG_PATH);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  writeFileSync(CONFIG_PATH, JSON.stringify(config, null, 2) + "\n");
}

/** Upsert a repo entry in the global config. Creates the file if needed. */
export function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): void {
  const global = loadGlobalConfig() ?? { server_url: serverUrl, repos: {} };
  global.server_url = serverUrl;
  global.repos[gitRoot] = repo;
  saveGlobalConfig(global);
}

// ---------------------------------------------------------------------------
// Resolved config (what consumers use)
// ---------------------------------------------------------------------------

/** Resolve BrainConfig for the current repo from ~/.config/brain.json. */
export function loadConfig(): BrainConfig | undefined {
  const gitRoot = findGitRoot(process.cwd());
  const global = loadGlobalConfig();
  if (global && gitRoot && global.repos[gitRoot]) {
    const repo = global.repos[gitRoot];
    return { server_url: global.server_url, workspace: repo.workspace, api_key: repo.api_key };
  }
  return undefined;
}

export function requireConfig(): BrainConfig {
  const config = loadConfig();
  if (!config) {
    console.error("Brain not configured. Run: brain init");
    process.exit(1);
  }
  return config;
}

// ---------------------------------------------------------------------------
// Dir cache (unchanged — runtime state for project mapping + sessions)
// ---------------------------------------------------------------------------

function ensureBrainDir(): void {
  const dir = dirname(DIR_CACHE_PATH);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
}

export function loadDirCache(): Record<string, DirCacheEntry> {
  if (!existsSync(DIR_CACHE_PATH)) return {};
  try {
    return JSON.parse(readFileSync(DIR_CACHE_PATH, "utf-8")) as Record<string, DirCacheEntry>;
  } catch {
    return {};
  }
}

export function saveDirCache(cache: Record<string, DirCacheEntry>): void {
  ensureBrainDir();
  writeFileSync(DIR_CACHE_PATH, JSON.stringify(cache, null, 2) + "\n");
}

export function getDirCacheEntry(directory: string): DirCacheEntry | undefined {
  const cache = loadDirCache();
  return cache[directory];
}

export function setDirCacheEntry(directory: string, entry: DirCacheEntry): void {
  const cache = loadDirCache();
  cache[directory] = entry;
  saveDirCache(cache);
}

