 48→// ---------------------------------------------------------------------------
 49→// Step 1: Auth
 50→// ---------------------------------------------------------------------------
 51→
 52→async function setupAuth(serverUrl: string, workspaceId: string, gitRoot: string): Promise<string> {
 53→  // Check if already configured for this repo
 54→  const global = loadGlobalConfig();
 55→  const existing = global?.repos[gitRoot];
 56→  if (existing && existing.workspace === workspaceId) {
 57→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 58→    return workspaceId;
 59→  }
 60→
 61→  const initResult = await BrainHttpClient.initApiKey(serverUrl, workspaceId);
 62→  saveRepoConfig(serverUrl, gitRoot, {
 63→    workspace: workspaceId,
 64→    api_key: initResult.api_key,
 65→  });
 66→  console.log(`✓ Auth: API key saved for ${gitRoot} → workspace "${initResult.workspace.name}"`);
 67→  return initResult.workspace.name;
 68→}
 69→
 70→// ---------------------------------------------------------------------------
 71→// Step 2: .mcp.json
 72→// ---------------------------------------------------------------------------
 73→
 74→function setupMcpJson(gitRoot: string): void {
 75→  const mcpPath = join(gitRoot, ".mcp.json");
 76→  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
 77→
 78→  if (existsSync(mcpPath)) {
 79→    try {
 80→      mcp = JSON.parse(readFileSync(mcpPath, "utf-8"));
 81→      mcp.mcpServers ??= {};
 82→    } catch {
 83→      // Corrupted file — overwrite
 84→    }
 85→  }
 86→
 87→  mcp.mcpServers.brain = { command: "brain", args: ["mcp"] };
 88→  writeFileSync(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
 89→  console.log("✓ MCP: .mcp.json updated");
 90→}
 91→
 92→// ---------------------------------------------------------------------------
 93→// Step 3: .claude/settings.json hooks
 94→// ---------------------------------------------------------------------------
 95→
 96→type HookEntry = { type: string; command?: string; prompt?: string };
 97→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
 98→
 99→function setupClaudeHooks(gitRoot: string): void {
100→  const claudeDir = join(gitRoot, ".claude");
101→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
102→
103→  const settingsPath = join(claudeDir, "settings.json");
104→  let settings: Record<string, unknown> = {};
105→
106→  if (existsSync(settingsPath)) {
107→    try {
108→      settings = JSON.parse(readFileSync(settingsPath, "utf-8"));
109→    } catch {
110→      // Corrupted — start fresh but preserve nothing
111→    }
112→  }
113→
114→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
115→  let added = 0;
116→
117→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
118→    hooks[event] ??= [];
119→
120→    // Check if Brain hook already exists in this event
121→    const hasBrain = hooks[event].some((group) =>
122→      group.hooks?.some(
123→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
124→      ),
125→    );
126→
127→    if (!hasBrain) {
128→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
129→      added++;
130→    }
131→  }
132→
133→  settings.hooks = hooks;
134→  writeFileSync(settingsPath, JSON.stringify(settings, null, 2) + "\n");
135→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
136→}
137→
138→// ---------------------------------------------------------------------------
139→// Step 4: CLAUDE.md
140→// ---------------------------------------------------------------------------
141→
142→const MARKER_START = "<!-- brain-plugin-start -->";
143→const MARKER_END = "<!-- brain-plugin-end -->";
144→
145→function setupClaudeMd(gitRoot: string): void {
146→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
147→  let content = "";
148→
149→  if (existsSync(claudeMdPath)) {
150→    content = readFileSync(claudeMdPath, "utf-8");
151→  }
152→
153→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
154→
155→  const startIdx = content.indexOf(MARKER_START);
156→  const endIdx = content.indexOf(MARKER_END);
157→
158→  if (startIdx !== -1 && endIdx !== -1) {
159→    // Replace existing block
160→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
161→  } else {
162→    // Append
163→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
164→    content = content + separator + brainBlock + "\n";
165→  }
166→
167→  writeFileSync(claudeMdPath, content);
168→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
169→}
170→
171→// ---------------------------------------------------------------------------
172→// Step 5: Skills
173→// ---------------------------------------------------------------------------
174→
175→function setupSkills(gitRoot: string): void {
176→  const commandsDir = join(gitRoot, ".claude", "commands");
177→  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
178→
179→  let count = 0;
180→  for (const [filename, content] of Object.entries(BRAIN_SKILLS)) {
181→    writeFileSync(join(commandsDir, filename), content + "\n");
182→    count++;
183→  }
184→
185→  console.log(`✓ Skills: ${count} commands installed to .claude/commands/`);
186→}
187→
188→// ---------------------------------------------------------------------------
189→// Step 6: Git hooks
190→// ---------------------------------------------------------------------------
191→
192→export function installGitHooks(gitRoot?: string): void {
193→  const root = gitRoot ?? findGitRoot(process.cwd());
194→  if (!root) {
195→    console.log("  No .git directory found — skipping git hook installation.");
196→    return;
197→  }
198→
199→  const hooksDir = join(root, ".git", "hooks");
200→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
201→
202→  const preCommitPath = join(hooksDir, "pre-commit");
203→  const postCommitPath = join(hooksDir, "post-commit");
204→  const preCommitScript = `#!/bin/sh
205→# Brain pre-commit hook: check for task completion and unlogged decisions
206→brain check-commit
207→`;
208→
209→  if (!existsSync(preCommitPath)) {
210→    writeFileSync(preCommitPath, preCommitScript);
211→    chmodSync(preCommitPath, 0o755);
212→    console.log("✓ Git: pre-commit hook installed");
213→  } else {
214→    console.log("✓ Git: pre-commit hook already exists");
215→  }
216→
217→  // Remove legacy Brain post-commit hook
218→  if (existsSync(postCommitPath)) {
219→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
220→    const isBrainManaged =
221→      postCommitContent.includes("Brain post-commit hook") &&
222→      postCommitContent.includes("brain log-commit");
223→    if (isBrainManaged) {
224→      unlinkSync(postCommitPath);
225→      console.log("  Removed legacy Brain post-commit hook");
226→    }
227→  }
228→}
